var e=[{id:`L3_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`대체 병사를 얼마나 많이 끌고 온 거야? 가도 가도 끝이 없어!`,JPN:`いったいどれだけたくさんの兵士を連れてきているの？　どこまで行っても終わりが見えないわ！`,ENG:`Just how many soldiers did they bring over? The wave is endless!`,TWN:`到底帶來了多少士兵啊？怎麼沒完沒了！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`증원이 끊이질 않네요. 아무래도 저희 생각을 읽은 모양인데요.`,JPN:`増援が絶えませんね。どうやらこちらの意図が読まれたようです。`,ENG:`They keep sending in more troops. I think they read our minds.`,TWN:`增援不斷啊。看來他們知道我們在想什麼。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`뭐, 가장 큰 문제는 이 분들이 모두 마왕의 힘으로 강해졌다는 점이겠지만요.`,JPN:`まぁ、最も大きな問題はこの方々が全員、魔王の力によって強化されているという点ですけどね。`,ENG:`Well, the biggest issue is that they've been heightened with the Demon Lord's power.`,TWN:`嗯，最大的問題是他們全都是依靠魔王之力變強的吧？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`하하, 이거 벌써부터 손목이 욱신거려서 큰일이네요.`,JPN:`はは、もう手首が痛くなってきてしまいましたよ。`,ENG:`Ha ha, my fingers are already starting to ache.`,TWN:`哈哈，手腕已經開始痠了，這下可糟了。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_LAUGH`}}}},{id:`L9_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`부상자 옆에서 엄살 피우기야, 선배?`,JPN:`怪我人の前で大袈裟に言わないでよ、先輩！`,ENG:`Are you seriously fussing over finger pain when you're standing next to an injured person?`,TWN:`你這是在傷患旁邊裝可憐嗎，前輩？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_LAUGH`}}}},{id:`L15_1`,type:`dialog`,speaker:`KNIGHT_NPC_CHIEF_NULL`,text:{KOREA:`나는 영광스러운 수도 방위 기사단! 7번대 대장 루지에!`,JPN:`私は栄光ある首都防衛騎士団！　七番隊隊長ルージ！`,ENG:`I am Rougié, the seventh captain of the Capital Defense Knights!`,TWN:`我是榮耀的首都護衛騎士團第7小隊的隊長，盧吉爾！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`KNIGHT_NPC_CHIEF_NULL`,text:{KOREA:`구원을 방해하겠다면 용서하지……`,JPN:`救いの邪魔をする者は、許さ……`,ENG:`Those who stand in the way of salvation will not be–`,TWN:`如果你們想妨礙救贖，我是不會……`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`KNIGHT_NPC_CHIEF_NULL`,text:{KOREA:`우읏?!`,JPN:`ううっ！？`,ENG:`Uuuoh?!`,TWN:`唔唔？！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`저리 비켜!!`,JPN:`どいてっ！！`,ENG:`Out of the way!`,TWN:`讓開！！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`KNIGHT_NPC_CHIEF_NULL`,text:{KOREA:`크억……!`,JPN:`くあっ……！`,ENG:`Kuh...!`,TWN:`咳呃……！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`},R:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`KNIGHT_NPC_NULL_NULL`,text:{KOREA:`대장님!`,JPN:`隊長！`,ENG:`Captain!`,TWN:`隊長！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`},R:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`KNIGHT_NPC_CHIEF_NULL`,text:{KOREA:`난 신경 쓰지 말고 싸워라……! 적은 고작 넷이다!`,JPN:`私のことは気にせずに戦え……！　敵はたかだか四人だ！`,ENG:`Keep fighting...! There are only four of them!`,TWN:`別管我，繼續……戰鬥！敵人就只有四個人！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`},R:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L28_1`,type:`dialog`,speaker:`KNIGHT_NPC_NULL_NULL`,text:{KOREA:`빌어먹을 이방인들……!`,JPN:`クソッたれの異邦人ども……！`,ENG:`Damned outsiders...!`,TWN:`可惡的外邦人……！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`KNIGHT_NPC_NULL_NULL`,text:{KOREA:`7번대 돌격! 우리도 대장님을 따라 끝까지 싸운다!`,JPN:`七番隊突撃！　我々も隊長に従い、最後まで戦う！`,ENG:`7th squad, charge! We will fight until the very end!`,TWN:`第7小隊突擊！我們也要追隨隊長，和敵人奮戰到底！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`KNIGHT_NPC_CHIEF_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};